#include<bits/stdc++.h>
using namespace std;
long long n,m,q,t,a[100005],head=1,add,ans[7100005],len,u,v;
bool cmp(long long x,long long y){return x>y;}
queue<long long> lft,rit;
int main(){
    cin>>n>>m>>q>>u>>v>>t;
    for(int i=1;i<=n;i++)cin>>a[i];
    sort(a+1,a+n+1,cmp);
    for(int i=1;i<=m;i++){
        if(lft.empty()&&rit.empty()){
            long long x=a[head++];
            lft.push((long long)((x+add)*u/v)-q-add);
            rit.push((x+add)-(long long)((x+add)*u/v)-q-add);
            if(i%t==0)cout<<x+add<<" ";
        }
        else{
            long long x;
            if(head>n)x=max(lft.front(),rit.front());
            else x=max({a[head],lft.front(),rit.front()});
            if(x==a[head]&&head<=n)head++;
            else if(x==lft.front())lft.pop();
            else rit.pop();
            lft.push((long long)((x+add)*u/v)-q-add);
            rit.push((x+add)-(long long)((x+add)*u/v)-q-add);
            if(i%t==0)cout<<x+add<<" ";
        }
        add+=q;
    }
    cout<<endl;
    for(int i=head;i<=n;i++){
        ans[++len]=a[i]+add;
    }
    while(!lft.empty()){
        long long x=lft.front()+add;
        lft.pop();
        ans[++len]=x;
    }
    while(!rit.empty()){
        long long x=rit.front()+add;
        rit.pop();
        ans[++len]=x;
    }
    sort(ans+1,ans+len+1,cmp);
    for(int i=1;i<=len;i++)
        if(i%t==0)cout<<ans[i]<<" ";
    return 0;
}
